	import org.json.JSONArray;
	import org.json.JSONObject; 
	import sailpoint.object.Identity;
	import org.apache.commons.logging.Log;
	import org.apache.commons.logging.LogFactory;
	
    private static Log logger = LogFactory.getLog("sailpoint.services.asc.Gsuite"); 

    public String returnValue(Object value){
        if(void ==value || value == null){
          return "";
        }
        else{
          return value.toString();
        }
    }

    List retList = new ArrayList();
  
    JSONObject locationJson = new JSONObject();

    locationJson.put("type", "desk");
    locationJson.put("area", "");
    locationJson.put("floorName", "");
    locationJson.put("floorSection", "");
    locationJson.put("deskCode", "");
    locationJson.put("buildingId",returnValue(identity.getAttribute("buildingId")));

    retList.add(locationJson.toString());

    logger.debug(" retList:" + retList);
    return retList;
